arguments.file_text:
@rendermode InteractiveServer

<div class="@DropZoneClass"
     @ondragenter="HandleDragEnter"
     @ondragover="HandleDragOver"
     @ondragleave="HandleDragLeave"
     @ondrop="HandleDrop"
     @ondragenter:preventDefault
     @ondragover:preventDefault
     @ondrop:preventDefault>
    <InputFile OnChange="OnFilesSelected" multiple class="file-drop-input" />
    <p class="file-drop-text">Drag &amp; drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-drop-list">
        @foreach (var file in _files)
        {
            <li class="@(file.Error is not null ? "file-entry file-entry-error" : "file-entry")">
                @if (file.Error is not null)
                {
                    <span class="file-error">@file.Info.Name &mdash; @file.Error</span>
                }
                else
                {
                    <span class="file-info">@file.Info.Name (@FormatSize(file.Info.Size)) &mdash; @file.Info.Type</span>
                }
                <button class="file-remove-btn" @onclick="() => RemoveFile(file)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    public record FileInfo(string Name, long Size, string Type);

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private List<FileEntry> _files = new();
    private bool _isDragOver;

    private string DropZoneClass => _isDragOver ? "file-drop-zone file-drop-zone-highlight" : "file-drop-zone";

    private record FileEntry(FileInfo Info, string? Error);

    private void HandleDragEnter() => _isDragOver = true;
    private void HandleDragOver() => _isDragOver = true;
    private void HandleDragLeave() => _isDragOver = false;

    private async Task HandleDrop(DragEventArgs e)
    {
        _isDragOver = false;
        // File data comes through InputFile's OnChange
    }

    private async Task OnFilesSelected(InputFileChangeEventArgs e)
    {
        _isDragOver = false;
        const long maxSize = 10 * 1024 * 1024; // 10 MB

        foreach (var file in e.GetMultipleFiles(100))
        {
            var info = new FileInfo(file.Name, file.Size, file.ContentType);
            var error = file.Size > maxSize ? $"File exceeds 10 MB limit ({FormatSize(file.Size)})" : null;
            _files.Add(new FileEntry(info, error));
        }

        await NotifyParent();
    }

    private async Task RemoveFile(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _files.Where(f => f.Error is null).Select(f => f.Info).ToList();
        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };
}

.file-drop-zone {
    position: relative;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 200px;
    border: 2px dashed #90a4ae;
    border-radius: 8px;
    background-color: #fafafa;
    transition: background-color 0.2s, border-color 0.2s;
    padding: 2rem;
}

.file-drop-zone-highlight {
    background-color: #e3f2fd;
    border-color: #1976d2;
}

.file-drop-input {
    position: absolute;
    inset: 0;
    opacity: 0;
    cursor: pointer;
}

.file-drop-text {
    color: #607d8b;
    font-size: 1.1rem;
    pointer-events: none;
}

.file-drop-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.5rem 0.75rem;
    border: 1px solid #e0e0e0;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-entry-error {
    border-color: #e53935;
    background-color: #ffebee;
}

.file-info {
    color: #333;
}

.file-error {
    color: #c62828;
}

.file-remove-btn {
    margin-left: 1rem;
    background: none;
    border: 1px solid #bdbdbd;
    border-radius: 4px;
    padding: 0.25rem 0.5rem;
    cursor: pointer;
    color: #555;
}

.file-remove-btn:hover {
    background-color: #ef5350;
    color: #fff;
    border-color: #ef5350;
}

