toolArgs.file_text:
.file-drop-zone {
    position: relative;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 200px;
    border: 2px dashed #90a4ae;
    border-radius: 8px;
    background-color: #fafafa;
    transition: background-color 0.2s, border-color 0.2s;
    padding: 2rem;
}

.file-drop-zone-highlight {
    background-color: #e3f2fd;
    border-color: #1976d2;
}

.file-drop-input {
    position: absolute;
    inset: 0;
    opacity: 0;
    cursor: pointer;
}

.file-drop-text {
    color: #607d8b;
    font-size: 1.1rem;
    pointer-events: none;
}

.file-drop-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.5rem 0.75rem;
    border: 1px solid #e0e0e0;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-entry-error {
    border-color: #e53935;
    background-color: #ffebee;
}

.file-info {
    color: #333;
}

.file-error {
    color: #c62828;
}

.file-remove-btn {
    margin-left: 1rem;
    background: none;
    border: 1px solid #bdbdbd;
    border-radius: 4px;
    padding: 0.25rem 0.5rem;
    cursor: pointer;
    color: #555;
}

.file-remove-btn:hover {
    background-color: #ef5350;
    color: #fff;
    border-color: #ef5350;
}

